<span class="line"><span style="color:#F8F8F2;">    data </span><span style="color:#F92672;">=</span><span style="color:#F8F8F2;"> df.iloc[:, </span><span style="color:#AE81FF;">1</span><span style="color:#F8F8F2;">:].apply(</span><span style="color:#66D9EF;font-style:italic;">lambda</span><span style="color:#FD971F;font-style:italic;"> x</span><span style="color:#F8F8F2;">: </span><span style="color:#E6DB74;">&#39; &#39;</span><span style="color:#F8F8F2;">.join(x.dropna()), </span><span style="color:#FD971F;font-style:italic;">axis</span><span style="color:#F92672;">=</span><span style="color:#AE81FF;">1</span><span style="color:#F8F8F2;">)</span></span>
