<span class="line"><span style="color:#66D9EF;font-style:italic;">def</span><span style="color:#A6E22E;"> train_and_evaluate</span><span style="color:#F8F8F2;">(</span><span style="color:#FD971F;font-style:italic;">vectorizer_params</span><span style="color:#F8F8F2;">, </span><span style="color:#FD971F;font-style:italic;">train_data</span><span style="color:#F8F8F2;">, </span><span style="color:#FD971F;font-style:italic;">train_labels</span><span style="color:#F8F8F2;">, </span><span style="color:#FD971F;font-style:italic;">val_data</span><span style="color:#F8F8F2;">, </span><span style="color:#FD971F;font-style:italic;">val_labels</span><span style="color:#F8F8F2;">, </span><span style="color:#FD971F;font-style:italic;">model_filename</span><span style="color:#F8F8F2;">):</span></span>
